namespace SecureLoggingExample
{
    /// <summary>
    /// Utility class for sanitizing and masking sensitive data before logging.
    /// </summary>
    public static class LogSanitizer
    {
        private static readonly HashSet<string> SensitiveHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization",
            "Cookie",
            "Set-Cookie",
            "X-API-Key",
            "X-Auth-Token",
            "Proxy-Authorization",
            "X-CSRF-Token",
            "X-Forwarded-For" // Can be PII in some jurisdictions
        };

        private static readonly HashSet<string> SafeHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Content-Type",
            "Content-Length",
            "Accept",
            "Accept-Encoding",
            "Accept-Language",
            "Cache-Control",
            "User-Agent",
            "Host",
            "X-Request-ID",
            "X-Correlation-ID"
        };

        public static Dictionary<string, string> GetSafeHeaders(IHeaderDictionary headers)
        {
            var safeHeaders = new Dictionary<string, string>();
            foreach (var header in headers)
            {
                if (SensitiveHeaders.Contains(header.Key))
                {
                    safeHeaders[header.Key] = "[REDACTED]";
                }
                else if (SafeHeaders.Contains(header.Key))
                {
                    safeHeaders[header.Key] = header.Value.ToString();
                }
                else
                {
                    // Unknown headers - redact by default (allowlist approach)
                    safeHeaders[header.Key] = "[REDACTED-UNKNOWN]";
                }
            }
            return safeHeaders;
        }

        public static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email)) return "[empty]";
            var parts = email.Split('@');
            if (parts.Length != 2) return "[invalid-email]";
            var local = parts[0];
            var masked = local.Length <= 2
                ? "***"
                : local[0] + "***" + local[local.Length - 1];
            return masked + "@" + parts[1];
        }

        public static string MaskSensitiveValue(string value)
        {
            if (string.IsNullOrEmpty(value)) return "[empty]";
            if (value.Length <= 4) return "****";
            return value.Substring(0, 2) + new string('*', value.Length - 4) + value.Substring(value.Length - 2);
        }

        public static string MaskUserId(string userId)
        {
            if (string.IsNullOrEmpty(userId)) return "[empty]";
            // Show only last 4 characters for correlation
            if (userId.Length <= 4) return "****";
            return new string('*', userId.Length - 4) + userId.Substring(userId.Length - 4);
        }

        /// <summary>
        /// Sanitize request body by removing known sensitive fields.
        /// Only log structure/field names, never values of sensitive fields.
        /// </summary>
        public static string SanitizeRequestBody(string body)
        {
            if (string.IsNullOrEmpty(body)) return "[empty]";

            try
            {
                var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(body);
                if (obj == null) return "[null-body]";

                var sensitiveFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
                {
                    "password", "passwd", "pwd", "secret",
                    "creditCard", "credit_card", "cardNumber", "card_number",
                    "cvv", "cvc", "securityCode",
                    "ssn", "socialSecurityNumber", "social_security_number",
                    "token", "accessToken", "access_token", "refreshToken", "refresh_token",
                    "apiKey", "api_key",
                    "pin", "securityAnswer", "security_answer",
                    "dateOfBirth", "date_of_birth", "dob",
                    "bankAccount", "bank_account", "routingNumber", "routing_number"
                };

                var piiFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
                {
                    "email", "phone", "phoneNumber", "phone_number",
                    "address", "streetAddress", "street_address",
                    "firstName", "first_name", "lastName", "last_name", "name",
                    "fullName", "full_name"
                };

                var sanitized = new Dictionary<string, string>();
                foreach (var kvp in obj)
                {
                    if (sensitiveFields.Contains(kvp.Key))
                    {
                        sanitized[kvp.Key] = "[REDACTED]";
                    }
                    else if (piiFields.Contains(kvp.Key))
                    {
                        sanitized[kvp.Key] = "[PII-REDACTED]";
                    }
                    else
                    {
                        // Log non-sensitive fields but truncate long values
                        var val = kvp.Value?.ToString() ?? "null";
                        sanitized[kvp.Key] = val.Length > 100 ? val.Substring(0, 100) + "..." : val;
                    }
                }

                return JsonConvert.SerializeObject(sanitized);
            }
            catch
            {
                // If not JSON, log only the content length and type
                return $"[non-json-body, length={body.Length}]";
            }
        }

        /// <summary>
        /// Sanitize exception messages which may contain sensitive data
        /// </summary>
        public static string SanitizeExceptionForLogging(Exception ex)
        {
            // Remove potential connection strings, file paths with usernames, etc.
            var message = ex.Message;

            // Redact anything that looks like a connection string
            message = System.Text.RegularExpressions.Regex.Replace(
                message,
                @"(Server|Data Source|Initial Catalog|User Id|Password|Integrated Security)[^;""]*",
                "[CONNECTION-STRING-REDACTED]",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);

            // Redact file paths that might contain usernames
            message = System.Text.RegularExpressions.Regex.Replace(
                message,
                @"[A-Za-z]:\\Users\\[^\\]+",
                @"[PATH-REDACTED]",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);

            return message;
        }
    }

